"""Export routes — generate and download candidate data."""

import html

from pathlib import Path

from fastapi import APIRouter, Request, Form
from fastapi.responses import FileResponse, HTMLResponse

from src.web.app import templates
from src.modules.export import export_candidates

router = APIRouter()


@router.get("/", response_class=HTMLResponse)
async def export_page(request: Request):
    """Render export page."""
    return templates.TemplateResponse("export.html", {"request": request})


@router.post("/download")
async def download_export(
    request: Request,
    fmt: str = Form("excel"),
    include_messages: bool = Form(False),
):
    """Generate export file and return as download."""
    try:
        path = export_candidates(
            output_format=fmt,
            include_messages=include_messages,
        )

        if not path or not Path(path).exists():
            return HTMLResponse('<p><mark>导出失败: 没有数据</mark></p>', status_code=400)

        filename = Path(path).name
        media_type = (
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
            if fmt == "excel"
            else "text/csv"
        )

        return FileResponse(
            path=path,
            filename=filename,
            media_type=media_type,
        )

    except Exception as e:
        return HTMLResponse(f'<p><mark>导出失败: {html.escape(str(e))}</mark></p>', status_code=500)

"""Pipeline checkpoint manager for resume capability."""

import json
import os
import tempfile
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Dict, List, Optional, Set

from loguru import logger


CHECKPOINT_DIR = Path("data/.checkpoints")


class CheckpointManager:
    """Manages pipeline checkpoint save/load for resume support."""

    def __init__(self, checkpoint_id: Optional[str] = None):
        CHECKPOINT_DIR.mkdir(parents=True, exist_ok=True)

        if checkpoint_id:
            self.checkpoint_path = CHECKPOINT_DIR / f"{checkpoint_id}.json"
        else:
            ts = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")
            self.checkpoint_path = CHECKPOINT_DIR / f"pipeline_{ts}.json"

        self._data: Dict[str, Any] = {}

    def save(
        self,
        keywords: tuple,
        template: str,
        variables: dict,
        company: tuple,
        location: Optional[str],
        max_pages: int,
        batch_pages: int,
        skip_messaged: bool,
        interactive: bool,
        completed_pages: int,
        sent_ids: List[str],
        seen_ids: List[str],
        total_results: Optional[dict] = None,
        mode: str = "recommend",
        dry_run: bool = False,
    ) -> None:
        self._data = {
            "created_at": self._data.get("created_at", datetime.now(timezone.utc).isoformat()),
            "updated_at": datetime.now(timezone.utc).isoformat(),
            "params": {
                "keywords": list(keywords),
                "template": template,
                "variables": variables,
                "company": list(company) if company else [],
                "location": location,
                "max_pages": max_pages,
                "batch_pages": batch_pages,
                "skip_messaged": skip_messaged,
                "interactive": interactive,
                "mode": mode,
                "dry_run": dry_run,
            },
            "progress": {
                "completed_pages": completed_pages,
                "sent_ids": sent_ids,
                "seen_ids": seen_ids,
                "total_results": total_results or {},
            },
        }

        try:
            tmp_fd, tmp_path = tempfile.mkstemp(
                dir=self.checkpoint_path.parent, suffix=".tmp"
            )
            try:
                with os.fdopen(tmp_fd, "w", encoding="utf-8") as f:
                    json.dump(self._data, f, ensure_ascii=False, indent=2)
                os.replace(tmp_path, self.checkpoint_path)
            except BaseException:
                try:
                    os.unlink(tmp_path)
                except OSError:
                    pass
                raise
            logger.debug(f"Checkpoint saved: {self.checkpoint_path}")
        except Exception as e:
            logger.error(f"Failed to save checkpoint: {e}")
            raise

    @classmethod
    def load_latest(cls) -> Optional["CheckpointManager"]:
        CHECKPOINT_DIR.mkdir(parents=True, exist_ok=True)
        files = sorted(CHECKPOINT_DIR.glob("pipeline_*.json"), key=lambda p: p.stat().st_mtime, reverse=True)

        if not files:
            return None

        try:
            mgr = object.__new__(cls)
            mgr.checkpoint_path = files[0]
            mgr._data = {}
            with open(files[0], "r", encoding="utf-8") as f:
                mgr._data = json.load(f)
            logger.info(f"Loaded checkpoint: {files[0]}")
            return mgr
        except Exception as e:
            logger.error(f"Failed to load checkpoint: {e}")
            return None

    @property
    def params(self) -> Dict[str, Any]:
        return self._data.get("params", {})

    @property
    def progress(self) -> Dict[str, Any]:
        return self._data.get("progress", {})

    @property
    def completed_pages(self) -> int:
        return self.progress.get("completed_pages", 0)

    @property
    def sent_ids(self) -> List[str]:
        return list(self.progress.get("sent_ids", []))

    @property
    def seen_ids(self) -> Set[str]:
        return set(self.progress.get("seen_ids", []))

    @property
    def total_results(self) -> Dict[str, int]:
        return self.progress.get("total_results", {})

    @property
    def summary(self) -> str:
        p = self.params
        pr = self.progress
        created = self._data.get("created_at", "unknown")
        updated = self._data.get("updated_at", "unknown")
        mode = p.get("mode", "recommend")
        return (
